"""
Polymarket Wallet Analysis Script
Fetches trade activity, positions, and P/L for specified wallets.
"""
import requests
import json
from collections import defaultdict
from datetime import datetime

WALLETS = [
    "0xd0d6053c3c37e727402d84c14069780d360993aa",
    "0xa9ae84ee529dbec0c6634b08cd97d3f13f7d74f5",
    "0x63ce342161250d705dc0b16df89036c8e5f9ba9a",
    "0xd84c2b6d65dc596f49c7b6aadd6d74ca91e407b9",
]

DATA_API = "https://data-api.polymarket.com"

def short_addr\(addr\):
    return f"{addr[:6]}..{addr[-4:]}"

def fetch_json\(url, params=None, label=""\):
    try:
        resp = requests.get\(url, params=params, timeout=15\)
        if resp.status_code == 200:
            data = resp.json\(\)
            return data
        else:
            print\(f"  [{label}] HTTP {resp.status_code}: {resp.text[:200]}"\)
            return None
    except Exception as e:
        print\(f"  [{label}] Error: {e}"\)
        return None


def fetch_activity\(wallet, limit=500\):
    params = {"user": wallet, "type": "TRADE", "limit": limit}
    return fetch_json\(f"{DATA_API}/activity", params=params, label="activity"\)


def fetch_profit\(wallet\):
    params = {"user": wallet}
    return fetch_json\(f"{DATA_API}/profit", params=params, label="profit"\)


def fetch_positions\(wallet\):
    params = {"user": wallet}
    return fetch_json\(f"{DATA_API}/positions", params=params, label="positions"\)


def fetch_profile\(wallet\):
    params = {"user": wallet}
    return fetch_json\(f"{DATA_API}/profile", params=params, label="profile"\)


def fetch_earnings\(wallet\):
    params = {"user": wallet}
    return fetch_json\(f"{DATA_API}/earnings", params=params, label="earnings"\)


def analyze_wallet\(wallet\):
    tag = short_addr\(wallet\)
    print\(f"\\n{'='*80}"\)
    print\(f"  WALLET: {wallet}"\)
    print\(f"  Tag:    {tag}"\)
    print\(f"{'='*80}"\)

    # ---- 1. Activity \(trades\) ----
    print\(f"\\n--- Trade Activity \(limit=500\) ---"\)
    activity = fetch_activity\(wallet, limit=500\)

    if activity and isinstance\(activity, list\) and len\(activity\) > 0:
        trades = activity
        print\(f"  Total trades returned: {len\(trades\)}"\)

        buy_count = 0
        sell_count = 0
        total_volume = 0.0
        markets = set\(\)
        dates = []

        for t in trades:
            side = t.get\("side"\) or t.get\("type"\) or "?"
            side_upper = str\(side\).upper\(\)

            if "BUY" in side_upper:
                buy_count += 1
            elif "SELL" in side_upper:
                sell_count += 1

            size = float\(t.get\("size", 0\) or t.get\("amount", 0\) or 0\)
            price = float\(t.get\("price", 0\) or 0\)
            usd_val = size * price if price > 0 else size
            total_volume += usd_val

            title = t.get\("title"\) or t.get\("market"\) or t.get\("question"\) or t.get\("conditionId"\) or "unknown"
            markets.add\(str\(title\)[:80]\)

            ts = t.get\("timestamp"\) or t.get\("createdAt"\) or t.get\("date"\) or ""
            if ts:
                dates.append\(str\(ts\)\)

        print\(f"  BUY trades:   {buy_count}"\)
        print\(f"  SELL trades:  {sell_count}"\)
        print\(f"  Other:        {len\(trades\) - buy_count - sell_count}"\)
        print\(f"  Total Volume: ${total_volume:,.2f} USDC \(approx\)"\)

        print\(f"\\n  Unique Markets \({len\(markets\)}\):"\)
        for m in sorted\(markets\):
            print\(f"    - {m}"\)

        if dates:
            dates_sorted = sorted\(dates\)
            print\(f"\\n  Date range: {dates_sorted[0]} ... {dates_sorted[-1]}"\)
            print\(f"  Most recent 5 trades:"\)
            for d in dates_sorted[-5:]:
                print\(f"    {d}"\)

        # Sample trade schema
        print\(f"\\n  Sample trade \(first\):"\)
        sample = trades[0]
        for k, v in sample.items\(\):
            print\(f"    {k}: {str\(v\)[:120]}"\)

    elif activity and isinstance\(activity, dict\):
        print\(f"  Response is dict. Keys: {list\(activity.keys\(\)\)}"\)
        for k, v in activity.items\(\):
            print\(f"    {k}: {str\(v\)[:200]}"\)
    else:
        print\(f"  No activity data returned \(got: {type\(activity\).__name__ if activity is not None else 'None'}\)"\)

    # ---- 2. Profit endpoint ----
    print\(f"\\n--- Profit Data ---"\)
    profit = fetch_profit\(wallet\)
    if profit:
        if isinstance\(profit, list\):
            print\(f"  Returned {len\(profit\)} profit records"\)
            total_pnl = 0
            for p in profit[:5]:
                print\(f"    {json.dumps\(p, default=str\)[:200]}"\)
            for p in profit:
                pnl = float\(p.get\("profit", 0\) or p.get\("pnl", 0\) or p.get\("realized_profit", 0\) or 0\)
                total_pnl += pnl
            if total_pnl != 0:
                print\(f"  Estimated total P/L: ${total_pnl:,.2f}"\)
        elif isinstance\(profit, dict\):
            print\(f"  Keys: {list\(profit.keys\(\)\)}"\)
            for k, v in profit.items\(\):
                print\(f"    {k}: {str\(v\)[:200]}"\)
    else:
        print\(f"  No profit data"\)

    # ---- 3. Positions endpoint ----
    print\(f"\\n--- Positions ---"\)
    positions = fetch_positions\(wallet\)
    if positions:
        if isinstance\(positions, list\):
            print\(f"  {len\(positions\)} positions"\)
            total_invested = 0
            total_current = 0
            for pos in positions[:10]:
                title = pos.get\("title"\) or pos.get\("market"\) or pos.get\("conditionId"\) or "?"
                size = float\(pos.get\("size", 0\) or 0\)
                avg_price = float\(pos.get\("avgPrice", 0\) or pos.get\("price", 0\) or 0\)
                cur_price = float\(pos.get\("curPrice", 0\) or pos.get\("currentPrice", 0\) or 0\)
                side = pos.get\("side"\) or pos.get\("outcome"\) or "?"
                pnl = float\(pos.get\("pnl", 0\) or pos.get\("profit", 0\) or 0\)

                invested = size * avg_price
                current = size * cur_price
                total_invested += invested
                total_current += current

                print\(f"    {str\(title\)[:60]}"\)
                print\(f"      Side={side}, Size={size:.2f}, AvgPrice={avg_price:.4f}, CurPrice={cur_price:.4f}, PnL={pnl:.2f}"\)

            if len\(positions\) > 10:
                print\(f"    ... and {len\(positions\) - 10} more positions"\)

            if total_invested > 0:
                print\(f"\\n  Total invested \(shown\): ${total_invested:,.2f}"\)
                print\(f"  Total current \(shown\):  ${total_current:,.2f}"\)
                print\(f"  Unrealized P/L \(shown\): ${total_current - total_invested:,.2f}"\)

            if positions:
                print\(f"\\n  Sample position keys: {list\(positions[0].keys\(\)\)}"\)
        elif isinstance\(positions, dict\):
            print\(f"  Keys: {list\(positions.keys\(\)\)}"\)
            for k, v in positions.items\(\):
                print\(f"    {k}: {str\(v\)[:200]}"\)
    else:
        print\(f"  No positions data"\)

    # ---- 4. Profile endpoint ----
    print\(f"\\n--- Profile ---"\)
    profile = fetch_profile\(wallet\)
    if profile:
        if isinstance\(profile, dict\):
            for k, v in profile.items\(\):
                print\(f"    {k}: {str\(v\)[:200]}"\)
        elif isinstance\(profile, list\) and len\(profile\) > 0:
            print\(f"  {len\(profile\)} records"\)
            for item in profile[:3]:
                print\(f"    {json.dumps\(item, default=str\)[:200]}"\)
    else:
        print\(f"  No profile data"\)

    # ---- 5. Earnings endpoint ----
    print\(f"\\n--- Earnings ---"\)
    earnings = fetch_earnings\(wallet\)
    if earnings:
        if isinstance\(earnings, list\):
            print\(f"  {len\(earnings\)} earning records"\)
            total_earn = 0
            for e in earnings[:5]:
                print\(f"    {json.dumps\(e, default=str\)[:200]}"\)
            for e in earnings:
                amt = float\(e.get\("amount", 0\) or e.get\("earnings", 0\) or 0\)
                total_earn += amt
            if total_earn != 0:
                print\(f"  Total earnings: ${total_earn:,.2f}"\)
        elif isinstance\(earnings, dict\):
            for k, v in earnings.items\(\):
                print\(f"    {k}: {str\(v\)[:200]}"\)
    else:
        print\(f"  No earnings data"\)


def try_alternative_endpoints\(\):
    """Try alternative API endpoints to discover available data."""
    print\(f"\\n{'='*80}"\)
    print\(f"  EXPLORING ALTERNATIVE ENDPOINTS"\)
    print\(f"{'='*80}"\)

    wallet = WALLETS[0]
    tag = short_addr\(wallet\)

    endpoints = [
        \(f"{DATA_API}/trades", {"user": wallet, "limit": 10}\),
        \(f"{DATA_API}/users/{wallet}", {}\),
        \(f"{DATA_API}/user", {"address": wallet}\),
        \(f"https://clob.polymarket.com/profile/{wallet}", {}\),
        \(f"https://gamma-api.polymarket.com/query", {"user": wallet, "limit": 5}\),
        \(f"{DATA_API}/resolve", {"limit": 5}\),
        \(f"https://gamma-api.polymarket.com/events", {"limit": 3, "active": True}\),
        \(f"https://clob.polymarket.com/rewards/{wallet}", {}\),
    ]

    for url, params in endpoints:
        print\(f"\\n  Trying: {url}"\)
        print\(f"    Params: {params}"\)
        data = fetch_json\(url, params=params, label="explore"\)
        if data:
            if isinstance\(data, list\):
                print\(f"    Got list of {len\(data\)} items"\)
                if data and isinstance\(data[0], dict\):
                    print\(f"    Sample keys: {list\(data[0].keys\(\)\)[:15]}"\)
                    # Print first item truncated
                    for k2, v2 in list\(data[0].items\(\)\)[:8]:
                        print\(f"      {k2}: {str\(v2\)[:100]}"\)
            elif isinstance\(data, dict\):
                print\(f"    Got dict with keys: {list\(data.keys\(\)\)[:15]}"\)
                for k2, v2 in list\(data.items\(\)\)[:8]:
                    print\(f"      {k2}: {str\(v2\)[:100]}"\)
        else:
            print\(f"    No data / error"\)


def compute_pl_from_trades\(wallet\):
    """Attempt to compute P/L from trade activity."""
    tag = short_addr\(wallet\)
    activity = fetch_activity\(wallet, limit=500\)
    if not activity or not isinstance\(activity, list\) or len\(activity\) == 0:
        print\(f"\\n  [{tag}] No trades to compute P/L from"\)
        return

    print\(f"\\n--- P/L Estimation from Trades [{tag}] ---"\)

    by_market = defaultdict\(list\)
    for t in activity:
        key = t.get\("conditionId"\) or t.get\("slug"\) or t.get\("title"\) or t.get\("market"\) or "unknown"
        by_market[key].append\(t\)

    print\(f"  Trades span {len\(by_market\)} unique markets/conditions"\)

    grand_cost = 0
    grand_shares = 0

    for market_key, trades in sorted\(by_market.items\(\), key=lambda x: len\(x[1]\), reverse=True\)[:15]:
        net_shares = 0
        cost_basis = 0
        for t in trades:
            side = str\(t.get\("side", ""\)\).upper\(\)
            size = float\(t.get\("size", 0\) or 0\)
            price = float\(t.get\("price", 0\) or 0\)

            if "BUY" in side:
                net_shares += size
                cost_basis += size * price
            elif "SELL" in side:
                net_shares -= size
                cost_basis -= size * price

        title_str = ""
        for t in trades:
            title_str = t.get\("title"\) or t.get\("question"\) or str\(market_key\)
            break
        title_str = str\(title_str\)[:70]

        grand_cost += cost_basis
        grand_shares += abs\(net_shares\)

        print\(f"\\n    Market: {title_str}"\)
        print\(f"      Trades: {len\(trades\)}, Net shares: {net_shares:+.2f}, Cost basis: ${cost_basis:,.2f}"\)

    print\(f"\\n  Grand totals: Cost basis=${grand_cost:,.2f}, Total shares={grand_shares:,.2f}"\)


if __name__ == "__main__":
    print\("=" * 80\)
    print\("  POLYMARKET WALLET ANALYSIS"\)
    print\(f"  Date: {datetime.now\(\).strftime\('%Y-%m-%d %H:%M:%S'\)}"\)
    print\("=" * 80\)

    for wallet in WALLETS:
        analyze_wallet\(wallet\)

    try_alternative_endpoints\(\)

    print\(f"\\n\\n{'='*80}"\)
    print\(f"  P/L ESTIMATION FROM TRADE DATA"\)
    print\(f"{'='*80}"\)
    for wallet in WALLETS:
        compute_pl_from_trades\(wallet\)

    print\(f"\\n\\nDone."\)
PYEOF)
